from dataclasses import dataclass

@dataclass(frozen=True)
class PairKey2:
    a: str
    b: str

def canonical(a, b):
    x, y = sorted([a, b])
    return PairKey2(x, y)

print(canonical('B', 'A'))
print(canonical('A', 'B') == canonical('B', 'A'))

